CREATE TABLE IF NOT EXISTS `ops_eval_case` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'Primary key',
  `case_id` varchar(64) NOT NULL COMMENT 'Evaluation case id',
  `case_name` varchar(128) NOT NULL COMMENT 'Case name',
  `service_name` varchar(128) NOT NULL COMMENT 'Target service name',
  `alert_payload_json` text COMMENT 'Synthetic alert payload',
  `problem` varchar(2000) NOT NULL COMMENT 'Incident problem description',
  `expected_root_cause` varchar(512) NOT NULL COMMENT 'Expected root cause keyword',
  `expected_evidence_types_json` varchar(1000) NOT NULL COMMENT 'Expected evidence keywords',
  `expected_tools_json` varchar(1000) NOT NULL COMMENT 'Expected tool names',
  `golden_summary` text COMMENT 'Golden summary',
  `severity` varchar(32) NOT NULL DEFAULT 'P1' COMMENT 'Severity',
  `tags` varchar(512) DEFAULT NULL COMMENT 'Tags',
  `enabled` tinyint NOT NULL DEFAULT 1 COMMENT 'Enabled flag',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Create time',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Update time',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_case_id` (`case_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='Ops Agent evaluation cases';

CREATE TABLE IF NOT EXISTS `ops_eval_run` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'Primary key',
  `run_id` varchar(64) NOT NULL COMMENT 'Evaluation run id',
  `case_id` varchar(64) NOT NULL COMMENT 'Evaluation case id',
  `diagnosis_id` varchar(64) DEFAULT NULL COMMENT 'Diagnosis id',
  `status` varchar(32) NOT NULL COMMENT 'Run status',
  `top1_root_cause_hit` tinyint NOT NULL DEFAULT 0 COMMENT 'Top1 root cause hit',
  `top3_root_cause_hit` tinyint NOT NULL DEFAULT 0 COMMENT 'Top3 root cause hit',
  `required_evidence_coverage` decimal(8,4) NOT NULL DEFAULT 0 COMMENT 'Evidence coverage',
  `unsupported_conclusion_count` int NOT NULL DEFAULT 0 COMMENT 'Unsupported conclusion count',
  `tool_call_count` int NOT NULL DEFAULT 0 COMMENT 'Tool call count',
  `diagnosis_latency_ms` bigint NOT NULL DEFAULT 0 COMMENT 'Diagnosis latency ms',
  `final_status` varchar(32) DEFAULT NULL COMMENT 'Final diagnosis status',
  `summary_json` text COMMENT 'Run summary',
  `error_message` varchar(1000) DEFAULT NULL COMMENT 'Error message',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Create time',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Update time',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_run_id` (`run_id`),
  KEY `idx_case_id` (`case_id`),
  KEY `idx_diagnosis_id` (`diagnosis_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='Ops Agent evaluation runs';

CREATE TABLE IF NOT EXISTS `ops_eval_metric` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'Primary key',
  `run_id` varchar(64) NOT NULL COMMENT 'Evaluation run id',
  `case_id` varchar(64) NOT NULL COMMENT 'Evaluation case id',
  `metric_name` varchar(128) NOT NULL COMMENT 'Metric name',
  `metric_value` decimal(12,4) NOT NULL DEFAULT 0 COMMENT 'Metric value',
  `metric_detail_json` text COMMENT 'Metric detail',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Create time',
  PRIMARY KEY (`id`),
  KEY `idx_run_id` (`run_id`),
  KEY `idx_case_id` (`case_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='Ops Agent evaluation metrics';

INSERT IGNORE INTO `ops_eval_case`
(`case_id`, `case_name`, `service_name`, `alert_payload_json`, `problem`, `expected_root_cause`, `expected_evidence_types_json`, `expected_tools_json`, `golden_summary`, `severity`, `tags`)
