INSERT IGNORE INTO `ops_eval_case`
(`case_id`, `case_name`, `service_name`, `alert_payload_json`, `problem`, `expected_root_cause`, `expected_evidence_types_json`, `expected_tools_json`, `golden_summary`, `severity`, `tags`)
VALUES
('eval-db-pool-hikari-timeout', 'Hikari pool timeout with pending requests', 'ops-demo-service', '{}',
 'P1: checkout API 5xx and latency increased. Prometheus signals include hikari_connections_usage_percent near 95%, hikari_connections_pending > 10, hikari_connection_timeout_total increasing, and http_5xx_rate_percent rising. ELK samples contain SQLTransientConnectionException: HikariPool - Connection is not available. SkyWalking DB spans are slower than application spans.',
 'connection_pool_exhausted', '["hikari","connection","timeout","db","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Connection pool exhaustion should be supported by Hikari metrics, connection timeout logs, slow DB spans, and database connection pool runbook.', 'P1', 'db,hikari,timeout,5xx'),
('eval-db-pool-no-log', 'Hikari saturation with negative log evidence', 'ops-demo-service', '{}',
 'P1: payment API has high latency. Prometheus shows hikari active connections close to max and pending requests increasing. ELK and SkyWalking may return NO_ANOMALY because the timeout is swallowed by upstream retry. The expected answer should be probable connection pool exhaustion, not an unsupported definitive claim.',
 'connection_pool_exhausted', '["hikari","pending","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Agent should treat Prometheus Hikari saturation plus Runbook as enough for probable root cause even when log/trace are negative.', 'P1', 'db,hikari,negative-evidence'),
('eval-http-5xx-application-stack', 'Application exception with 5xx and stack trace', 'ops-demo-service', '{}',
 'P1: create order endpoint returns 5xx. Prometheus shows http_server_requests 5xx. ELK contains NullPointerException at OrderService.createOrder and traceId samples. SkyWalking error traces point to the same endpoint.',
 'application_exception', '["5xx","nullpointerexception","trace","error"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Application exception should be confirmed by 5xx metrics, concentrated stack traces, and failed trace samples.', 'P1', 'http,5xx,exception'),
('eval-http-5xx-gateway-layer', 'Gateway layer 5xx without application error', 'ops-demo-service', '{}',
 'P1: external users see 502/503. Prometheus reports 5xx spike, but ELK has no application exception and SkyWalking has no matching error trace. Gateway runbook suggests upstream reset, route error, or health-check inconsistency.',
 'gateway_5xx', '["5xx","gateway","no_anomaly","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'The correct result is a probable gateway or HTTP layer 5xx root cause with negative application log/trace evidence, not a fabricated DB/JVM root cause.', 'P1', 'http,gateway,5xx,negative-evidence'),
('eval-rpc-dubbo-timeout', 'Dubbo downstream timeout causing slow requests', 'ops-demo-service', '{}',
 'P1: order submit p95 latency > 3s. ELK contains RpcException: Invoke remote method timeout. SkyWalking slow trace has downstream dubbo provider span taking 2800ms. Prometheus latency and 5xx increased during the same window.',
 'downstream_timeout', '["timeout","dubbo","latency","trace"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Downstream RPC timeout should be supported by timeout logs, slow downstream span, and latency metrics.', 'P1', 'rpc,dubbo,timeout'),
('eval-rpc-feign-timeout', 'HTTP client timeout to downstream service', 'ops-demo-service', '{}',
 'P1: coupon query endpoint has high latency and partial 5xx. ELK contains ResourceAccessException read timed out and Feign client timeout. SkyWalking trace shows downstream HTTP span timeout.',
 'downstream_timeout', '["timeout","feign","http","trace"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'HTTP downstream timeout should cite client timeout logs, downstream spans, and request latency.', 'P1', 'rpc,feign,http-client'),
('eval-redis-read-timeout', 'Redis read timeout causing degraded checkout', 'ops-demo-service', '{}',
 'P1: checkout degradation. ELK contains RedisCommandTimeoutException and Lettuce command timed out. SkyWalking cache span shows Redis GET timeout. Prometheus 5xx and latency rise together.',
 'redis_timeout', '["redis","timeout","trace","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Redis timeout should be supported by Redis timeout logs, cache span timeout, latency metrics, and Redis runbook.', 'P1', 'redis,timeout'),
('eval-redis-pool-exhaustion', 'Redis connection pool pressure', 'ops-demo-service', '{}',
 'P2: cache access latency increased. Logs include Redis connection pool exhausted and command timeout. Trace samples point to Redis dependency. Prometheus application latency increases but DB metrics are normal.',
 'redis_timeout', '["redis","connection","timeout","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Redis dependency pressure should be ranked above DB/JVM when Redis logs and spans are stronger.', 'P2', 'redis,pool,dependency'),
('eval-jvm-full-gc-heap-pressure', 'Full GC heap pressure causing p99 latency', 'ops-demo-service', '{}',
 'P1: p99 latency spikes. Prometheus shows jvm_memory_used_bytes increasing and jvm_gc_pause_seconds max high. ELK contains Full GC and GC overhead messages. No downstream timeout dominates the window.',
 'full_gc_pressure', '["gc","heap","memory","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Full GC pressure should be supported by memory metrics, GC pause evidence, and JVM runbook.', 'P1', 'jvm,gc,memory'),
('eval-jvm-oom-risk', 'JVM memory pressure with OOM risk', 'ops-demo-service', '{}',
 'P1: memory keeps rising and request latency oscillates. Logs include OutOfMemoryError risk and repeated Full GC. Prometheus shows heap usage and GC pause abnormal.',
 'full_gc_pressure', '["outofmemoryerror","gc","memory","latency"]', '["query_prometheus","query_elasticsearch","query_runbook"]',
 'JVM memory pressure should be explained through heap, GC pause, and OOM-risk evidence.', 'P1', 'jvm,oom,gc'),
('eval-mq-consumer-lag', 'Consumer lag and backlog delaying processing', 'ops-demo-service', '{}',
 'P2: order fulfillment delayed. Prometheus/MQ metrics show consumer lag and message backlog. ELK contains consume batch timeout and retry logs. HTTP layer is healthy.',
 'consumer_lag', '["mq","consumer","lag","backlog"]', '["query_prometheus","query_elasticsearch","query_runbook"]',
 'MQ backlog should be supported by lag metrics, retry logs, and MQ runbook.', 'P2', 'mq,consumer,lag'),
('eval-mq-retry-storm', 'MQ retry storm causing backlog', 'ops-demo-service', '{}',
 'P2: delayed task queue grows. Logs contain repeated message retry and dead-letter warning. Prometheus shows backlog increasing, while Redis and DB evidence are weak.',
 'consumer_lag', '["mq","retry","backlog","runbook"]', '["query_prometheus","query_elasticsearch","query_runbook"]',
 'Retry storm and backlog should be treated as MQ consumer lag family.', 'P2', 'mq,retry,backlog'),
('eval-slow-sql-db-span', 'Slow SQL visible in database spans', 'ops-demo-service', '{}',
 'P1: product query endpoint p95 latency increased. SkyWalking DB span SELECT product_sku takes 2400ms. ELK contains slow query and lock wait timeout. Prometheus latency rises but Hikari pool is not exhausted.',
 'slow_sql', '["slow","sql","db","span"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Slow SQL should be supported by DB span latency, slow query logs, and slow SQL runbook, without misclassifying as connection pool exhaustion.', 'P1', 'db,slow-sql,trace'),
('eval-slow-sql-lock-wait', 'MySQL lock wait causing timeout', 'ops-demo-service', '{}',
 'P1: inventory update endpoint timeout. ELK contains Lock wait timeout exceeded; try restarting transaction. SkyWalking DB span is slow on update inventory. Prometheus p99 latency increased.',
 'slow_sql', '["lock","sql","db","timeout"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Lock wait should be diagnosed as database slow query/contention evidence, not generic HTTP 5xx.', 'P1', 'db,lock,slow-sql'),
('eval-cpu-saturation', 'CPU saturation causing latency and thread pressure', 'ops-demo-service', '{}',
 'P1: all endpoints become slower. Prometheus shows process_cpu_usage and system_cpu_usage high, tomcat_threads_busy increasing, but Hikari and Redis evidence are weak. ELK has hot loop warning in pricing calculation.',
 'cpu_saturation', '["cpu","usage","latency","thread"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'CPU saturation should be supported by CPU metrics, latency, thread pressure, and hot method hints.', 'P1', 'cpu,latency'),
('eval-thread-pool-saturation', 'Business executor saturation with queue backlog', 'ops-demo-service', '{}',
 'P1: async settlement tasks delayed and API timeout increases. Prometheus shows executor_active_threads close to max and tomcat_threads_busy high. ELK contains RejectedExecutionException and queue backlog.',
 'thread_pool_saturation', '["executor","thread","queue","rejected"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Thread pool saturation should be supported by executor metrics, rejected execution logs, and queue backlog evidence.', 'P1', 'thread-pool,executor'),
('eval-observability-gap-5xx', '5xx symptom with queried negative evidence', 'ops-demo-service', '{}',
 'P1: 5xx alert fired. Prometheus confirms 5xx rate increased. ELK returns NO_ANOMALY and SkyWalking returns NO_ANOMALY for the same window. Runbook says this may be gateway 5xx or observability gap. Agent should not invent DB, Redis, or JVM root cause.',
 'observability_gap', '["5xx","no_anomaly","observability","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'When only symptom metric exists and key data sources are negative, the correct result is investigation complete with probable HTTP layer or observability gap, not unsupported strong root cause.', 'P1', '5xx,observability-gap,negative-evidence'),
('eval-mixed-db-and-rpc', 'Mixed evidence where DB signal dominates RPC symptom', 'ops-demo-service', '{}',
 'P1: checkout latency and some downstream timeouts appear. Prometheus shows Hikari pending and connection timeout increasing before RPC timeout logs. SkyWalking indicates RPC timeout is downstream of DB wait in the same request path.',
 'connection_pool_exhausted', '["hikari","timeout","trace","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Agent should rank DB connection pool exhaustion above RPC timeout when DB evidence temporally precedes downstream timeout.', 'P1', 'mixed,db,rpc'),
('eval-mixed-gc-and-cpu', 'Mixed JVM and CPU evidence with GC root cause', 'ops-demo-service', '{}',
 'P1: CPU and latency increase together, but Prometheus also shows heap pressure and long GC pauses. ELK contains Full GC messages. Hot thread evidence is weak. Expected root cause is JVM memory/GC pressure.',
 'full_gc_pressure', '["gc","cpu","memory","runbook"]', '["query_prometheus","query_elasticsearch","query_skywalking_trace","query_runbook"]',
 'Agent should distinguish CPU as secondary symptom from GC/memory pressure as the dominant root cause.', 'P1', 'mixed,jvm,cpu');

